{"code": "import logging
import os
import io
import codecs

class FilePathContext:
    def __init__(self, path):
        self.filepath = path if isinstance(path, str) else path.filepath
    def open(self, mode):
        return open(self.filepath, mode)

def resolve_format(fmt, filepath):
    _, ext = os.path.splitext(filepath.lower())
    if ext in ['.tsv', '.txt']:
        return 'tsv'
    if ext in ['.yaml', '.yml']:
        return 'yaml'
    return None

def parse_exchange_table_file(f):
    header = f.readline()
    for line in f:
        parts = line.strip().split('\t')
        if len(parts) != 3:
            continue
        yield {'compound': parts[0], 'lower': float(parts[1]), 'upper': float(parts[2])}

def parse_exchange_yaml_file(context, f, default_compartment):
    for line in f:
        parts = line.strip().split(':')
        if len(parts) < 3:
            continue
        entry = {
            'compound': parts[0],
            'lower': float(parts[1]),
            'upper': float(parts[2]),
            'compartment': parts[3] if len(parts) > 3 else default_compartment
        }
        yield entry

class ParseError(Exception):
    pass

logger = logging.getLogger(__name__)

def parse_exchange_file(path, default_compartment):
    """Parse an exchange file (TSV or YAML) and yield compound entries.

    File format is auto-detected from content (first meaningful line).
    Lines starting with '#' are treated as comments and skipped.
    Compound names must be alphanumeric. Lower bound must be <= upper bound.
    UTF-8 BOM is automatically stripped.
    Empty files and whitespace-only files yield no entries.
    """
    context = FilePathContext(path)

    # Read raw bytes so we can strip a UTF-8 BOM ourselves
    with context.open('rb') as f:
        raw = f.read()

    # Empty file → no entries
    if not raw:
        return

    # Strip UTF-8 byte-order mark if present
    bom = codecs.BOM_UTF8
    if raw.startswith(bom):
        raw = raw[len(bom):]

    # Decode to text
    content = raw.decode('utf-8')

    # Whitespace-only content → no entries
    if not content.strip():
        return

    lines = content.splitlines(keepends=True)

    # --- Content-based format detection ---
    # Scan for the first non-comment, non-empty line
    first_meaningful = None
    for line in lines:
        stripped = line.lstrip()
        if stripped.startswith('#'):
            continue
        stripped_content = stripped.strip()
        if not stripped_content:
            continue
        first_meaningful = stripped_content
        break

    if first_meaningful is None:
        # All lines are comments or blank
        return

    # Detect TSV (tab-separated) vs YAML-like (colon-separated)
    if '\t' in first_meaningful:
        fmt = 'tsv'
    elif ':' in first_meaningful:
        fmt = 'yaml'
    else:
        raise ParseError(f"Unable to determine file format for {path}")

    # --- Strip comment lines ---
    filtered_lines = []
    for line in lines:
        if line.lstrip().startswith('#'):
            continue
        filtered_lines.append(line)

    filtered_content = ''.join(filtered_lines)
    f = io.StringIO(filtered_content)

    # Delegate to the appropriate helper parser
    if fmt == 'tsv':
        generator = parse_exchange_table_file(f)
    else:
        generator = parse_exchange_yaml_file(context, f, default_compartment)

    # --- Validate every yielded entry ---
    for entry in generator:
        compound = entry['compound']
        # Compound name must be alphanumeric (no special characters)
        if not compound.isalnum():
            continue
        # Lower bound must be <= upper bound
        if entry['lower'] > entry['upper']:
            continue
        yield entry
